// frontend/src/components/Dashboard/StatsCards.js
import React, { useState, useEffect } from 'react';
import {
  Grid,
  Card,
  CardContent,
  Typography,
  Box,
  Skeleton,
  useTheme
} from '@mui/material';
import {
  TrendingUp,
  TrendingDown,
  AccountBalance,
  ShowChart,
  Timeline,
  Percent,
  Receipt
} from '@mui/icons-material';

const StatsCards = ({ stats, loading, hideValues = false }) => {
  const theme = useTheme();
  const [commissionBalanceUsd, setCommissionBalanceUsd] = useState(0);

  useEffect(() => {
    // Função para buscar a cotação e atualizar o saldo em USD
    const updateCommissionBalance = async () => {
      if (stats && stats.operational_balance > 0) {
        try {
          // API pública da Bitget para cotação, não requer autenticação
          const response = await fetch('https://api.bitget.com/api/v2/spot/market/tickers?symbol=USDTBRL');
          if (!response.ok) {
            throw new Error('Network response was not ok');
          }
          const data = await response.json();

          if (data.code === '00000' && data.data && data.data.length > 0) {
            const brlPrice = parseFloat(data.data[0].lastPr);
            if (brlPrice > 0) {
              const usdValue = stats.operational_balance / brlPrice;
              setCommissionBalanceUsd(usdValue);
            }
          } else {
            // Fallback para taxa fixa se a API falhar
            setCommissionBalanceUsd(stats.operational_balance * 0.18);
          }
        } catch (error) {
          console.error("Failed to fetch BRL to USD rate:", error);
          // Fallback em caso de erro de rede
          setCommissionBalanceUsd(stats.operational_balance * 0.18);
        }
      } else if (stats) {
        // Se o saldo em BRL for 0, o saldo em USD também é 0
        setCommissionBalanceUsd(stats.operational_balance_usd || 0);
      }
    };

    updateCommissionBalance();
  }, [stats]); // Re-executa quando as estatísticas mudam

  const formatCurrency = (value) => {
    if (hideValues) return '$***';
    if (value === null || value === undefined) return '$0.00';
    const numValue = parseFloat(value);
    // Para valores muito pequenos (< 0.01), usar mais casas decimais
    if (Math.abs(numValue) < 0.01 && numValue !== 0) {
      return `$${numValue.toFixed(8)}`;
    }
    // Para valores pequenos (< 1), usar 6 casas decimais para mostrar precisão
    if (Math.abs(numValue) < 1) {
      return `$${numValue.toFixed(6)}`;
    }
    // Para valores maiores, usar 4 casas decimais para manter precisão
    return `$${numValue.toFixed(4)}`;
  };

  const formatPercentage = (value) => {
    // Percentuais permanecem visíveis
    if (value === null || value === undefined) return '0%';
    // Usar mais casas decimais para percentuais pequenos
    const decimals = Math.abs(value) < 1 ? 4 : 2;
    return `${value >= 0 ? '+' : ''}${value.toFixed(decimals)}%`;
  };

  const formatNumber = (value) => {
    if (hideValues) return '***';
    if (value === null || value === undefined) return '0';
    return new Intl.NumberFormat('pt-BR').format(value);
  };

  const getColorByValue = (value) => {
    if (value > 0) return theme.palette.success.main;
    if (value < 0) return theme.palette.error.main;
    return theme.palette.text.secondary;
  };

  const statsConfig = [
    {
      title: 'Lucro Aberto',
      value: stats?.unrealized_pnl_percentage,
      format: formatPercentage,
      icon: ShowChart,
      color: getColorByValue(stats?.unrealized_pnl_percentage || 0),
      description: hideValues ? '*** em operações abertas' : `${formatCurrency(stats?.unrealized_pnl || 0)} em operações abertas`
    },
    {
      title: 'PnL Realizado',
      value: stats?.realized_pnl,
      format: formatCurrency,
      icon: Timeline,
      color: getColorByValue(stats?.realized_pnl || 0),
      description: 'Lucro/Prejuízo de trades fechados'
    },
    {
      title: 'ROE Médio',
      value: stats?.average_roe,
      format: formatPercentage,
      icon: Percent,
      color: getColorByValue(stats?.average_roe || 0),
      description: 'Retorno sobre investimento médio'
    },
    {
      title: 'Total de Trades',
      value: stats?.total_trades,
      format: formatNumber,
      icon: ShowChart,
      color: theme.palette.primary.main,
      description: 'Número total de operações fechadas'
    },
    {
      title: 'Taxa de Acerto',
      value: stats?.win_rate,
      format: formatPercentage,
      icon: TrendingDown,
      color: getColorByValue(stats?.win_rate || 0),
      description: 'Percentual de trades lucrativos'
    },
    {
      title: 'Saldo para Comissão',
      value: commissionBalanceUsd,
      format: formatCurrency,
      icon: AccountBalance,
      color: stats?.can_open_positions === false ? theme.palette.error.main : theme.palette.success.main,
      description: stats?.can_open_positions === false 
        ? `🚫 BLOQUEADO - ${formatCurrency(stats?.total_commission_paid_usd || 0)} usado`
        : `Usado: ${formatCurrency(stats?.total_commission_paid_usd || 0)}\nComissão: ${((stats?.commission_rate || 0.35) * 100).toFixed(0)}%`,
      secondaryValue: stats?.operational_balance,
      secondaryFormat: (value) => hideValues ? 'Total: R$ ***' : `Total: R$ ${(value || 0).toFixed(2)}`,
      isBalanceCard: true,
      showUsageBar: true,
      usagePercentage: stats?.operational_balance_percentage || 0,
      isBlocked: stats?.can_open_positions === false
    },
    {
      title: 'Saldo - Futuros',
      value: stats?.account_balance_usd,
      format: formatCurrency,
      icon: AccountBalance,
      color: getColorByValue(stats?.account_balance_usd || 0),
      description: `Saldo total na exchange`,
      secondaryValue: stats?.account_balance_brl,
      secondaryFormat: (value) => hideValues ? 'R$ ***' : `R$ ${(value || 0).toFixed(2)}`,
      isBalanceCard: true,
      highlightDescription: true
    },
    {
      title: 'Recarregar Conta',
      value: null,
      format: () => '',
      icon: AccountBalance,
      color: theme.palette.primary.main,
      description: 'Plano recarregável sem assinatura',
      isRechargeCard: true,
      rechargeOptions: [
        { value: 'R$ 9', link: 'https://pay.hub.la/ekfJp2uXQ0S5ZBb65Otb', isTest: true },
        { value: 'R$ 50', link: 'https://pay.hub.la/MdORdaFcTzWvhT9IkZHP' },
        { value: 'R$ 100', link: 'https://pay.hub.la/mFfwQbUAqILTw8bfDXjo' },
        { value: 'R$ 200', link: 'https://pay.hub.la/EVrxnuDyf4JeB0uIYaFC' },
        { value: 'R$ 500', link: 'https://pay.hub.la/LmFhy6R6HP3fjoJxZe5z' }
      ]
    }
  ];

  if (loading) {
    return (
      <Grid container spacing={3}>
        {Array.from({ length: 6 }).map((_, index) => (
          <Grid item xs={12} sm={6} md={4} lg={2} key={index}>
            <Card sx={{ height: '100%' }}>
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                  <Skeleton variant="circular" width={40} height={40} sx={{ mr: 2 }} />
                  <Box sx={{ flexGrow: 1 }}>
                    <Skeleton variant="text" width="60%" />
                    <Skeleton variant="text" width="40%" />
                  </Box>
                </Box>
                <Skeleton variant="text" width="80%" height={32} />
                <Skeleton variant="text" width="60%" />
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>
    );
  }

  return (
    <Grid container spacing={3}>
      {statsConfig.map((stat, index) => {
        const IconComponent = stat.icon;

        return (
          <Grid item xs={12} sm={6} md={4} lg={2} key={index}>
            <Card
              sx={{
                height: '100%',
                transition: 'all 0.3s ease',
                '&:hover': {
                  transform: 'translateY(-4px)',
                  boxShadow: theme.shadows[8]
                }
              }}
            >
              <CardContent>
                <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                  <Box
                    sx={{
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      width: 40,
                      height: 40,
                      borderRadius: '50%',
                      bgcolor: `${stat.color}20`,
                      mr: 2
                    }}
                  >
                    <IconComponent sx={{ color: stat.color, fontSize: 20 }} />
                  </Box>
                  <Box sx={{ flexGrow: 1 }}>
                    <Typography
                      variant="caption"
                      color="text.secondary"
                      sx={{ fontWeight: 500 }}
                    >
                      {stat.title}
                    </Typography>
                  </Box>
                </Box>

                {stat.isRechargeCard ? (
                  <>
                    <Box sx={{ mb: 2 }}>
                      <Typography
                        variant="caption"
                        color="text.secondary"
                        sx={{
                          display: 'block',
                          lineHeight: 1.2
                        }}
                      >
                        {stat.description}
                      </Typography>
                    </Box>

                    <Grid container spacing={1}>
                      {stat.rechargeOptions.map((option, optionIndex) => (
                        <Grid item xs={option.isTest ? 12 : 6} key={optionIndex}>
                          <Box
                            component="a"
                            href={option.link}
                            target="_blank"
                            rel="noopener noreferrer"
                            sx={{
                              display: 'flex',
                              alignItems: 'center',
                              justifyContent: 'center',
                              p: 1,
                              border: option.isTest 
                                ? `2px solid ${theme.palette.warning.main}` 
                                : `1px solid ${theme.palette.primary.main}`,
                              borderRadius: 1,
                              textDecoration: 'none',
                              color: option.isTest 
                                ? theme.palette.warning.main 
                                : theme.palette.primary.main,
                              fontSize: '0.875rem',
                              fontWeight: 'bold',
                              transition: 'all 0.2s ease',
                              bgcolor: option.isTest 
                                ? `${theme.palette.warning.main}10` 
                                : 'transparent',
                              '&:hover': {
                                bgcolor: option.isTest 
                                  ? theme.palette.warning.main 
                                  : theme.palette.primary.main,
                                color: 'white'
                              }
                            }}
                          >
                            {option.isTest ? `🧪 ${option.value} (TESTE)` : option.value}
                          </Box>
                        </Grid>
                      ))}
                    </Grid>
                  </>
                ) : stat.isBalanceCard ? (
                  <>
                    <Typography
                      variant="h5"
                      sx={{
                        fontWeight: 'bold',
                        color: stat.color,
                        mb: 1,
                        fontSize: { xs: '1.25rem', sm: '1.5rem' }
                      }}
                    >
                      {stat.format(stat.value)}
                    </Typography>

                    {stat.secondaryValue !== undefined && stat.secondaryFormat && (
                      <Typography
                        variant="body2"
                        color="text.secondary"
                        sx={{
                          fontWeight: 'medium',
                          mb: 2
                        }}
                      >
                        {stat.secondaryFormat(stat.secondaryValue)}
                      </Typography>
                    )}

                    <Box sx={{ mb: 2 }}>
                      <Typography
                        variant="caption"
                        color="text.secondary"
                        sx={{ whiteSpace: 'pre-line' }}
                      >
                        {stat.description}
                      </Typography>
                    </Box>

                    {/* Barra de uso do saldo operacional */}
                    {stat.showUsageBar && (
                      <Box sx={{ mb: 2 }}>
                        <Box
                          sx={{
                            width: '100%',
                            height: 8,
                            bgcolor: theme.palette.grey[200],
                            borderRadius: 1,
                            overflow: 'hidden',
                            position: 'relative'
                          }}
                        >
                          <Box
                            sx={{
                              width: `${Math.min(stat.usagePercentage || 0, 100)}%`,
                              height: '100%',
                              bgcolor: stat.isBlocked 
                                ? theme.palette.error.main 
                                : stat.usagePercentage >= 90 
                                  ? theme.palette.warning.main 
                                  : stat.usagePercentage >= 75 
                                    ? theme.palette.warning.light 
                                    : theme.palette.success.main,
                              transition: 'all 0.3s ease'
                            }}
                          />
                          {/* Linha de alerta aos 95% */}
                          <Box
                            sx={{
                              position: 'absolute',
                              left: '95%',
                              top: 0,
                              width: 2,
                              height: '100%',
                              bgcolor: theme.palette.error.main,
                              opacity: 0.7
                            }}
                          />
                        </Box>
                        <Typography
                          variant="caption"
                          color={stat.isBlocked ? "error.main" : "text.secondary"}
                          sx={{
                            fontSize: '0.7rem',
                            mt: 0.5,
                            display: 'block',
                            textAlign: 'center',
                            fontWeight: stat.isBlocked ? 'bold' : 'normal'
                          }}
                        >
                          {stat.isBlocked ? '⚠️ Limite atingido!' : `Limite: 95%`}
                        </Typography>
                      </Box>
                    )}

                    {/* Espaçamento para igualar altura do card de recarga */}
                    <Box sx={{ height: stat.showUsageBar ? '24px' : '64px' }} />
                  </>
                ) : (
                  <Box>
                    <Typography
                      variant="h5"
                      sx={{ 
                        fontWeight: 'bold',
                        color: stat.color,
                        fontSize: { xs: '1.25rem', sm: '1.5rem' }
                      }}
                    >
                      {stat.format(stat.value)}
                    </Typography>
                    <Typography
                      variant="caption"
                      color="text.secondary"
                      sx={{ whiteSpace: 'pre-line' }}
                    >
                      {stat.description}
                    </Typography>
                  </Box>
                )}
              </CardContent>
            </Card>
          </Grid>
        );
      })}
    </Grid>
  );
};

export default StatsCards;
